//! Adversarial tests for scoring module and seed_archetypes.
//!
//! Attack vectors:
//! 1. SQL injection via base_position parameter in get_archetypes()
//! 2. Malformed JSON — verify seed_archetypes JSON serialization is safe
//! 3. Empty database — get_archetypes on empty DB returns empty vec
//! 4. Very long archetype name
//! 5. Duplicate archetype names — INSERT OR IGNORE handles correctly
//! 6. Unicode in archetype names
//! 7. Negative weights
//! 8. Zero weights — archetype with all zero weights

use rusqlite::Connection;
use fm_valuescout_lib::db;
use fm_valuescout_lib::scoring::{get_seed_archetypes, ArchetypeDefinition, ArchetypeWeightEntry, ArchetypeWeights};

/// Test 1: SQL injection via base_position parameter.
/// Malicious strings like "DC'; DROP TABLE archetypes; --" must be treated
/// as a literal position filter — never as executable SQL.
/// Expected: query returns empty (no archetype matches), not a crash.
#[test]
fn test_sql_injection_via_base_position() {
    let conn = Connection::open_in_memory().unwrap();
    db::create_tables(&conn).unwrap();
    db::seed_archetypes(&conn).unwrap();

    let malicious_inputs = [
        "DC'; DROP TABLE archetypes; --",
        "DC' OR '1'='1",
        "'; DELETE FROM archetypes; --",
        "DC\"; DROP TABLE archetypes; --",
        "DC' UNION SELECT * FROM players; --",
        "DC'); DROP TABLE archetypes; --",
    ];

    for malicious in malicious_inputs {
        let result = db::get_archetypes(&conn, Some(malicious));
        // Must not panic — query must remain safe.
        assert!(
            result.is_ok(),
            "SQL injection potential: get_archetypes panicked or errored on input '{}': {:?}",
            malicious,
            result
        );
        let archetypes = result.unwrap();
        // Malicious strings do not match any real position, so result must be empty.
        assert!(
            archetypes.is_empty(),
            "SQL injection may have succeeded: got {} archetypes for malicious input '{}'",
            archetypes.len(),
            malicious
        );
    }
}

/// Test 2: Malformed JSON — seed_archetypes JSON serialization must be safe.
/// We control the data (hardcoded in get_seed_archetypes), but we verify that
/// serde_json::to_string cannot produce malformed output for valid inputs, and
/// that the JSON is valid enough to deserialize back.
#[test]
fn test_seed_archetypes_json_round_trip() {
    let archetypes = get_seed_archetypes();
    for arch in &archetypes {
        let json_result = serde_json::to_string(&arch.weights);
        assert!(
            json_result.is_ok(),
            "serde_json::to_string failed for archetype '{}': {:?}",
            arch.name,
            json_result.err()
        );
        let json_str = json_result.unwrap();
        // Must be valid JSON.
        let parsed: ArchetypeWeights = serde_json::from_str(&json_str)
            .expect(&format!("valid JSON must deserialize for '{}': {}", arch.name, json_str));
        // Deserialized weights must match original counts.
        assert_eq!(
            parsed.in_possession.len(),
            arch.weights.in_possession.len(),
            "in_possession count mismatch for '{}' after round-trip",
            arch.name
        );
        assert_eq!(
            parsed.out_of_possession.len(),
            arch.weights.out_of_possession.len(),
            "out_of_possession count mismatch for '{}' after round-trip",
            arch.name
        );
    }
}

/// Test 2b: Malformed JSON injection — manually inject garbage JSON into the DB
/// via direct INSERT to verify get_archetypes does NOT try to parse the JSON column
/// (it only reads name/base_position, so it should remain unaffected).
#[test]
fn test_malformed_json_in_archetypes_table() {
    let conn = Connection::open_in_memory().unwrap();
    db::create_tables(&conn).unwrap();
    db::seed_archetypes(&conn).unwrap();

    // Inject a row with explicitly malformed JSON.
    let _inject_result = conn.execute(
        "INSERT OR IGNORE INTO archetypes (name, base_position, metric_weights_json) VALUES (?1, ?2, ?3)",
        rusqlite::params!["Malformed JSON Archetype", "DC", "{ this is not valid json \\x00 broken"],
    );
    // INSERT may fail or succeed — both are acceptable.
    // The key is that get_archetypes (which does NOT parse metric_weights_json)
    // must still work correctly on the valid rows.
    let result = db::get_archetypes(&conn, Some("DC"));
    assert!(
        result.is_ok(),
        "get_archetypes must remain safe even when table contains malformed JSON rows"
    );
    let archetypes = result.unwrap();
    // Valid archetypes (from seed_archetypes) must still be present.
    assert!(
        archetypes.len() >= 3,
        "expected at least 3 valid DC archetypes, got {}",
        archetypes.len()
    );
}

/// Test 3: Empty database — get_archetypes on empty DB returns empty vec.
#[test]
fn test_get_archetypes_empty_database() {
    let conn = Connection::open_in_memory().unwrap();
    db::create_tables(&conn).unwrap();
    // Do NOT seed archetypes.

    let all_archetypes = db::get_archetypes(&conn, None).unwrap();
    assert!(
        all_archetypes.is_empty(),
        "expected empty vec on empty DB, got {} archetypes",
        all_archetypes.len()
    );

    let filtered = db::get_archetypes(&conn, Some("DC")).unwrap();
    assert!(
        filtered.is_empty(),
        "expected empty vec for filter on empty DB, got {} archetypes",
        filtered.len()
    );
}

/// Test 4: Very long archetype name.
/// SQLite TEXT columns have no explicit limit, but we verify the system
/// handles oversized names gracefully (up to our practical limit of ~10KB).
#[test]
fn test_very_long_archetype_name() {
    let conn = Connection::open_in_memory().unwrap();
    db::create_tables(&conn).unwrap();

    let long_name = "A".repeat(10_000);
    let _inject_result = conn.execute(
        "INSERT OR IGNORE INTO archetypes (name, base_position, metric_weights_json) VALUES (?1, ?2, ?3)",
        rusqlite::params![&long_name, "DC", r#"{"in_possession":[],"out_of_possession":[]}"#],
    );
    // INSERT OR IGNORE — if it fails due to duplicate key it's not an error.
    // If it succeeds, verify get_archetypes still works.
    let result = db::get_archetypes(&conn, None);
    assert!(
        result.is_ok(),
        "get_archetypes must handle archetypes with very long names without error: {:?}",
        result.err()
    );
}

/// Test 5: Duplicate archetype names — INSERT OR IGNORE handles correctly.
#[test]
fn test_duplicate_archetype_names_ignored() {
    let conn = Connection::open_in_memory().unwrap();
    db::create_tables(&conn).unwrap();
    db::seed_archetypes(&conn).unwrap();

    let initial = db::get_archetypes(&conn, None).unwrap();
    let initial_count = initial.len();

    // Attempt to insert a duplicate.
    db::seed_archetypes(&conn).unwrap();

    let after = db::get_archetypes(&conn, None).unwrap();
    assert_eq!(
        after.len(),
        initial_count,
        "INSERT OR IGNORE must not create duplicate archetypes: expected {} but got {}",
        initial_count,
        after.len()
    );

    // Also verify the duplicate insert didn't corrupt data by checking names match.
    let mut initial_names: Vec<_> = initial.iter().map(|a| a.name.clone()).collect();
    let mut after_names: Vec<_> = after.iter().map(|a| a.name.clone()).collect();
    initial_names.sort();
    after_names.sort();
    assert_eq!(initial_names, after_names, "duplicate seed must not alter archetype list");
}

/// Test 6: Unicode in archetype names.
/// Verify that names containing various Unicode scripts are stored and retrieved correctly.
#[test]
fn test_unicode_archetype_names() {
    let conn = Connection::open_in_memory().unwrap();
    db::create_tables(&conn).unwrap();

    let unicode_names = [
        "Ball-Playing Defender ✓",           // check mark
        "防守型中場",                         // Chinese
        "Αμυντικός Χαφ",                    // Greek
        "دفاعي خط الوسط",                    // Arabic (RTL)
        "전술 스트라이커",                     // Korean
        "🛡️ Shield Defender",               // emoji
        "Ball-Playing Defender\t\n\r",       // control characters
    ];

    for name in &unicode_names {
        let result = conn.execute(
            "INSERT OR IGNORE INTO archetypes (name, base_position, metric_weights_json) VALUES (?1, ?2, ?3)",
            rusqlite::params![name, "DC", r#"{"in_possession":[],"out_of_possession":[]}"#],
        );
        // Each name gets its own row (unique names), so insert should succeed.
        assert!(
            result.is_ok(),
            "failed to insert archetype with Unicode name '{}': {:?}",
            name,
            result.err()
        );
    }

    // Verify all inserted Unicode archetypes are retrievable.
    let archetypes = db::get_archetypes(&conn, Some("DC")).unwrap();
    // At minimum we seeded 3 DC archetypes, plus the 7 Unicode ones.
    // If Unicode inserts were rejected, we still get at least the seeded 3.
    assert!(
        archetypes.len() >= 3,
        "expected at least 3 seeded DC archetypes, got {}",
        archetypes.len()
    );
}

/// Test 7: Negative weights.
/// Verify that negative weight values are accepted and stored (semantically they
/// invert the metric contribution, which is valid per ArchetypeWeightEntry.inverted=false
/// but a negative raw weight is mathematically unusual).
#[test]
fn test_negative_weights() {
    let conn = Connection::open_in_memory().unwrap();
    db::create_tables(&conn).unwrap();

    let negative_weights = ArchetypeWeights {
        in_possession: vec![
            ArchetypeWeightEntry { metric_name: "pas".into(), weight: -3.0, inverted: false },
        ],
        out_of_possession: vec![
            ArchetypeWeightEntry { metric_name: "tck".into(), weight: -1.0, inverted: false },
        ],
    };

    let json = serde_json::to_string(&negative_weights).unwrap();
    let result = conn.execute(
        "INSERT OR IGNORE INTO archetypes (name, base_position, metric_weights_json) VALUES (?1, ?2, ?3)",
        rusqlite::params!["Negative Weight Archetype", "DC", &json],
    );
    assert!(
        result.is_ok(),
        "seed_archetypes must accept negative weight values: {:?}",
        result.err()
    );

    // Verify it can be retrieved.
    let archetypes = db::get_archetypes(&conn, Some("DC")).unwrap();
    assert!(
        archetypes.iter().any(|a| a.name == "Negative Weight Archetype"),
        "negative weight archetype must be stored and retrievable"
    );
}

/// Test 8: Zero weights — archetype with all zero weights.
/// Zero weights should be accepted (player contributes nothing for those metrics).
#[test]
fn test_zero_weights() {
    let conn = Connection::open_in_memory().unwrap();
    db::create_tables(&conn).unwrap();

    let zero_weights = ArchetypeWeights {
        in_possession: vec![
            ArchetypeWeightEntry { metric_name: "pas".into(), weight: 0.0, inverted: false },
            ArchetypeWeightEntry { metric_name: "fir".into(), weight: 0.0, inverted: false },
        ],
        out_of_possession: vec![
            ArchetypeWeightEntry { metric_name: "tck".into(), weight: 0.0, inverted: false },
        ],
    };

    let json = serde_json::to_string(&zero_weights).unwrap();
    let result = conn.execute(
        "INSERT OR IGNORE INTO archetypes (name, base_position, metric_weights_json) VALUES (?1, ?2, ?3)",
        rusqlite::params!["Zero Weight Archetype", "DC", &json],
    );
    assert!(
        result.is_ok(),
        "seed_archetypes must accept zero weight values: {:?}",
        result.err()
    );

    // Verify it round-trips correctly via JSON.
    let parsed: ArchetypeWeights = serde_json::from_str(&json).unwrap();
    assert_eq!(parsed.in_possession.len(), 2);
    assert_eq!(parsed.out_of_possession.len(), 1);
    assert_eq!(parsed.in_possession[0].weight, 0.0);
}

/// Test 8b: Empty weights — archetype with NO weight entries.
/// An archetype with completely empty in/out lists is legal (Enganche has out_of_possession=[]).
#[test]
fn test_empty_weights_both_zero() {
    let conn = Connection::open_in_memory().unwrap();
    db::create_tables(&conn).unwrap();

    let empty_weights = ArchetypeWeights {
